import{_ as a,c as t,a2 as n,o as s}from"./chunks/framework.CoXjB5sU.js";const u=JSON.parse('{"title":"Elaboration of the \\"extension\\" type","description":"","frontmatter":{},"headers":[],"relativePath":"blog/path-elab.md","filePath":"blog/path-elab.md","lastUpdated":1679673438000}'),i={name:"blog/path-elab.md"};function o(p,e,l,r,c,h){return s(),t("div",null,e[0]||(e[0]=[n(`<h1 id="elaboration-of-the-extension-type" tabindex="-1">Elaboration of the &quot;extension&quot; type <a class="header-anchor" href="#elaboration-of-the-extension-type" aria-label="Permalink to &quot;Elaboration of the &quot;extension&quot; type&quot;">‚Äč</a></h1><p>Aya uses the so-called &quot;extension&quot; type (probably first-appeared <a href="https://arxiv.org/abs/1705.07442" target="_blank" rel="noreferrer">here</a>) as a generalized version of path type.</p><p>Instead of using the conventional path type, as in Cubical Agda:</p><ul><li><code>PathP (őĽ i ‚Üí A i) a b</code> for <code>a : A 0</code> and <code>b : A 1</code></li><li><code>őĽ i ‚Üí a : PathP (őĽ i ‚Üí A i) (a 0) (a 1)</code> for <code>a : A i</code></li><li><code>p i : A i</code> for <code>p : PathP (őĽ i ‚Üí A i) a b</code><ul><li><code>p 0 = a</code> and <code>p 1 = b</code></li></ul></li></ul><p>This type looks good, but it does not scale to higher dimensions. Consider, for example, the type of a square with four faces specified (from Agda&#39;s cubical library):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Square :</span></span>
<span class="line"><span>  {a‚āÄ‚āÄ a‚āÄ‚āĀ : A} (a‚āÄ‚āč : a‚āÄ‚āÄ ‚Č° a‚āÄ‚āĀ)</span></span>
<span class="line"><span>  {a‚āĀ‚āÄ a‚āĀ‚āĀ : A} (a‚āĀ‚āč : a‚āĀ‚āÄ ‚Č° a‚āĀ‚āĀ)</span></span>
<span class="line"><span>  (a‚āč‚āÄ : a‚āÄ‚āÄ ‚Č° a‚āĀ‚āÄ) (a‚āč‚āĀ : a‚āÄ‚āĀ ‚Č° a‚āĀ‚āĀ)</span></span>
<span class="line"><span>  ‚Üí Type _</span></span>
<span class="line"><span>Square a‚āÄ‚āč a‚āĀ‚āč a‚āč‚āÄ a‚āč‚āĀ = PathP (őĽ i ‚Üí a‚āč‚āÄ i ‚Č° a‚āč‚āĀ i) a‚āÄ‚āč a‚āĀ‚āč</span></span></code></pre></div><p>It gets even worse when the type is heterogeneous:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SquareP :</span></span>
<span class="line"><span>  (A : I ‚Üí I ‚Üí Type ‚Ąď)</span></span>
<span class="line"><span>  {a‚āÄ‚āÄ : A i0 i0} {a‚āÄ‚āĀ : A i0 i1} (a‚āÄ‚āč : PathP (őĽ j ‚Üí A i0 j) a‚āÄ‚āÄ a‚āÄ‚āĀ)</span></span>
<span class="line"><span>  {a‚āĀ‚āÄ : A i1 i0} {a‚āĀ‚āĀ : A i1 i1} (a‚āĀ‚āč : PathP (őĽ j ‚Üí A i1 j) a‚āĀ‚āÄ a‚āĀ‚āĀ)</span></span>
<span class="line"><span>  (a‚āč‚āÄ : PathP (őĽ i ‚Üí A i i0) a‚āÄ‚āÄ a‚āĀ‚āÄ) (a‚āč‚āĀ : PathP (őĽ i ‚Üí A i i1) a‚āÄ‚āĀ a‚āĀ‚āĀ)</span></span>
<span class="line"><span>  ‚Üí Type ‚Ąď</span></span>
<span class="line"><span>SquareP A a‚āÄ‚āč a‚āĀ‚āč a‚āč‚āÄ a‚āč‚āĀ = PathP (őĽ i ‚Üí PathP (őĽ j ‚Üí A i j) (a‚āč‚āÄ i) (a‚āč‚āĀ i)) a‚āÄ‚āč a‚āĀ‚āč</span></span></code></pre></div><p>We have decided to use a partial element to represent these faces, and so we can freely add or delete these a face, without having to explicitly write down all faces for generality. This leads to the following syntax:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>--------  ‚Üď type           ‚Üď the &quot;i = 0&quot; end is b</span></span>
<span class="line"><span>[| i |] (A i) {| i := a | ~ i := b |}</span></span>
<span class="line"><span>-- ^ interval         ^ the &quot;i = 1&quot; end is a</span></span></code></pre></div><p>The above type is equivalent to <code>PathP (őĽ i ‚Üí A i) a b</code>. We may use this to simplify the type signature of path concatenation:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>def concat {A : Type}</span></span>
<span class="line"><span>  (p : [| i |] A {| |})</span></span>
<span class="line"><span>  (q : [| i |] A {| ~ i := p 1 |})</span></span>
<span class="line"><span>  : [| i |] A {| ~ i := p 0 | i := q 1 |}</span></span></code></pre></div><p>It has fewer parameters than the conventional version:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>def concat {A : Type}</span></span>
<span class="line"><span>  {a b c : A}</span></span>
<span class="line"><span>  (p : Path A a b)</span></span>
<span class="line"><span>  (q : Path A b c)</span></span>
<span class="line"><span>  : Path A a c</span></span></code></pre></div><p>Now, how to implement this type? We have decided to overload lambdas and expressions as Cubical Agda did, but we have encountered several problems. Here&#39;s the story, in chronological order.</p><p>Below, we use &quot;type checking&quot; and we actually mean &quot;elaboration&quot;.</p><h2 id="first-attempt" tabindex="-1">First attempt <a class="header-anchor" href="#first-attempt" aria-label="Permalink to &quot;First attempt&quot;">‚Äč</a></h2><p><strong>Principle</strong>: do not annotate the terms (including variable references) with types, because this is going to harm efficiency and the code that tries to generate terms (now they&#39;ll have to generate the types as well, pain!).</p><p><strong>Problem</strong>: reduction of path application is type-directed, like <code>p 1</code> will reduce according to the type of <code>p</code>.</p><p><strong>Solution</strong>: annotate the path applications instead. Every time we do type checking &amp; we get a term of path type, we &quot;ő∑-expand&quot; it into a normal lambda expression with a path application inside. This secures the reduction of path applications.</p><p><strong>New Problem</strong>: we expand too much. In case we want to check the type of term against a path type, the term is actually ő∑-expanded and has a <em>ő†-type</em>. So, we have the manually write path lambdas everywhere, e.g. given <code>p : Path A a b</code>, and only <code>őĽ i ‚Üí p i</code> is a valid term of type <code>Path A a b</code>, not <code>p</code> (which is internally a lambda).</p><p><strong>Lesson</strong>: we need to preserve the types <em>somehow</em>, generate path applications only when necessary.</p><h2 id="second-attempt" tabindex="-1">Second attempt <a class="header-anchor" href="#second-attempt" aria-label="Permalink to &quot;Second attempt&quot;">‚Äč</a></h2><p><strong>New Solution</strong>: when checking something against a path type, we directly apply the boundary checks, instead of trying to invoke synthesize and unify the types. This eliminates a lot of <code>őĽ i ‚Üí p i</code> problems.</p><p><strong>New Problem</strong>: this is incompatible with implicit arguments. Consider the following problem:</p><ul><li>have: <code>idp : {a : A} -&gt; Path A a a</code></li><li>elaborated: <code>őĽ i ‚Üí idp i : {a : A} -&gt; I -&gt; A</code></li><li>check: <code>idp : Path Nat zero zero</code></li></ul><p>The new solution will try to apply the boundary before inserting the implicit arguments, which leads to type-incorrect terms.</p><p><strong>Lesson</strong>: we probably should not change the bidirectional type checking algorithm too much.</p><h2 id="third-attempt" tabindex="-1">Third attempt <a class="header-anchor" href="#third-attempt" aria-label="Permalink to &quot;Third attempt&quot;">‚Äč</a></h2><p><strong>New Solution</strong>: the type information is known in the bidirectional type checking anyway, so we only generate path applications during the type checking of application terms.</p><p>This has worked so far, with some unsolved problems (yet to be discussed):</p><ul><li>Is <code>p : [| i |] A {| |}</code> an instance of type <code>[| i |] A {| i := a |}</code>? <ul><li>Currently, Aya do not think so.</li></ul></li><li>Can we automatically turn Agda-style squares to its preferred version in generalized path type? <ul><li>Related issue: <a href="https://github.com/aya-prover/aya-dev/issues/530" target="_blank" rel="noreferrer">530</a></li><li>A sort of &quot;flattening&quot;</li></ul></li></ul><p>If you have any thoughts, feel free to reach out :)</p><h2 id="update-2023-03-24" tabindex="-1">Update (2023-03-24) <a class="header-anchor" href="#update-2023-03-24" aria-label="Permalink to &quot;Update (2023-03-24)&quot;">‚Äč</a></h2><p>The implementation has been updated to solve some the above problems partially. Essentially, we need to do one thing: coercive subtyping. Since the type checking already respects the type (say, does not change the type), it remains to insert an ő∑-expansion when the subtyping is invoked. We also need to store the boundary information in the path application term to have simple normalization algorithm.</p><p>Carlo Angiuli told me that in cooltt, the path type is <em>decoded</em> (in the sense of the universe √† la Tarski <code>el</code> operator) into a ő†-type that returns a cubical subtype, and since <code>el</code> is not required to be injective, this should be fine. At first, I was worried about the fibrancy of the path type, because a ő†-type into a subtype is not fibrant, but it turns out that this is unrelated. We don&#39;t talk about the fibrancy of the types, but only the fibrancy of the type <em>codes</em>.</p>`,36)]))}const b=a(i,[["render",o]]);export{u as __pageData,b as default};
